import { MakeLogicType, actions, kea, key, path, props, reducers } from 'kea'

export enum OutputTab {
    Results = 'results',
    Visualization = 'visualization',
    Both = 'both',
}

export interface OutputTabProps {
    tabId: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface outputPaneLogicValues {
    activeTab: OutputTab
    fullscreen: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface outputPaneLogicActions {
    setActiveTab: (tab: OutputTab) => {
        tab: OutputTab
    }
    setFullscreen: (fullscreen: boolean) => {
        fullscreen: boolean
    }
    toggleFullscreen: () => {
        value: true
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface outputPaneLogicMeta {
    key: string
}

export type outputPaneLogicType = MakeLogicType<
    outputPaneLogicValues,
    outputPaneLogicActions,
    OutputTabProps,
    outputPaneLogicMeta
>

export const outputPaneLogic = kea<outputPaneLogicType>([
    path(['data-warehouse', 'editor', 'outputPaneLogic']),
    props({} as OutputTabProps),
    key((props) => props.tabId),
    actions({
        setActiveTab: (tab: OutputTab) => ({ tab }),
        setFullscreen: (fullscreen: boolean) => ({ fullscreen }),
        toggleFullscreen: true,
    }),
    reducers({
        activeTab: [
            OutputTab.Results as OutputTab,
            {
                setActiveTab: (_, { tab }) => tab,
            },
        ],
        // Builder-only: expands the output pane over the query pane + database tree
        fullscreen: [
            false,
            {
                setFullscreen: (_, { fullscreen }) => fullscreen,
                toggleFullscreen: (state) => !state,
            },
        ],
    }),
])
